import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import path from 'path';

export default defineConfig({
  plugins: [react()],

  // Path aliases — import '@/components/Button' instead of '../../components/Button'
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
    },
  },

  // API proxy — forward /api/* to a backend running on port 3001
  server: {
    proxy: {
      '/api': 'http://localhost:3001',
    },
  },

  // Customise the dev server port
  server: {
    port: 3000,
  },

  // Set the public base path for sub-directory deployments (e.g. GitHub Pages)
  base: '/my-repo/',
});

// tsconfig.json — add compilerOptions.paths to match the Vite alias
