import { visualizer } from 'rollup-plugin-visualizer';
export default defineConfig({
  plugins: [
    react(),
    visualizer({ open: true }),  // opens stats.html after build
  ],
});

import logo from './assets/logo.svg';  // Vite returns the hashed URL
import styles from './Button.module.css'; // CSS Modules work out of the box

function Button() {
  return <img src={logo} alt="Logo" />;
}

/* Button.module.css */
.button {
  background: #3b82f6;
  color: white;
  padding: 0.5rem 1rem;
  border-radius: 4px;
}

import styles from './Button.module.css';

function Button({ label }: { label: string }) {
  return <button className={styles.button}>{label}</button>;
  // Rendered class: "_button_1k3m2_1" — unique, no collisions
}

// tailwind.config.js
export default {
  content: ['./index.html', './src/**/*.{ts,tsx}'],
  theme: { extend: {} },
  plugins: [],
};

/* src/index.css — add Tailwind directives */
@tailwind base;
@tailwind components;
@tailwind utilities;

import { lazy, Suspense } from 'react';

const Dashboard = lazy(() => import('./pages/Dashboard'));
const Settings  = lazy(() => import('./pages/Settings'));

function App() {
  return (
    <Suspense fallback={<div>Loading…</div>}>
      <Routes>
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/settings"  element={<Settings />} />
      </Routes>
    </Suspense>
  );
}

// vite.config.ts — add test configuration
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  test: {
    environment: 'jsdom',
    globals: true,
    setupFiles: './src/test/setup.ts',
  },
});

// src/Button.test.tsx
import { render, screen } from '@testing-library/react';
import { Button } from './Button';

test('renders label', () => {
  render(<Button label="Submit" />);
  expect(screen.getByText('Submit')).toBeInTheDocument();
});

// vite.config.ts — set base to the repo name
export default defineConfig({
  base: '/my-repo/',
});

{
  "compilerOptions": {
    "target": "ES2020",          // transpile to ES2020 (Vite's esbuild handles browser compat)
    "lib": ["ES2020", "DOM", "DOM.Iterable"],
    "module": "ESNext",          // keep ES modules
    "moduleResolution": "bundler", // Vite-aware resolution (replaces "node")
    "jsx": "react-jsx",          // automatic JSX runtime, no 'import React' needed
    "strict": true,              // enable all strict checks
    "noUnusedLocals": true,      // catch unused variables
    "noUnusedParameters": true,
    "noFallthroughCasesInSwitch": true
  }
}

export default defineConfig({
  plugins: [react()],
  build: {
    // Warn when a chunk exceeds this size (bytes)
    chunkSizeWarningLimit: 500,

    // Manual chunk splitting — keep vendor deps in a separate cacheable chunk
    rollupOptions: {
      output: {
        manualChunks: {
          vendor: ['react', 'react-dom'],
          router: ['react-router-dom'],
        },
      },
    },

    // Generate source maps for production error tracking (e.g. Sentry)
    sourcemap: true,
  },
});
